    -- Timing
    @api ctx:ppqToRow(ppqI, chan)
        @map:contract  per-chan binary search of rowPPQs after swing.toLogical(chan, ppqI); inverse of rowToPPQ
    @api ctx:rowToPPQ(row, chan)
        @map:contract  floor + swing.fromLogical, rounded to integer ppq; on-grid iff ctx:rowToPPQ(round(ppqToRow(p)), chan) == p
    @api ctx:snapRow(ppqI, chan)
    @api ctx:ppqPerRow()
    @api ctx:rowBeatInfo(row)
    @api ctx:barBeatSub(row)
@factory newTrackerView(tm, cm, cmgr)
  @map:contract  whenever a note's tail moves: rebases evt.frame to current alongside the new (endppq, endppqL) — writing endppqL alone would leave it incoherent with frame
  @map:contract  non-transient writes to FRAME_KEYS while a transient override is active short-circuit into releaseTransientFrame, whose recursive cm:assign fires the rebuild — so we return early to avoid double rebuild

  # Shapes
    @shape  grid = { cols = {<col>...}, chanFirstCol = {[chan]=i}, chanLastCol = {[chan]=i}, lane1Col = {[chan]=<col>}, numRows = int }
    @shape  gridCol = { type, midiChan, lane?, cc?, label, events, width, parts, stopPos, partAt, partStart, showDelay, cells={[y]=evt}, overflow={[y]=true}, offGrid={[y]=true}, ghosts={[y]={val,fromEvt,toEvt}}, tails? }
    @shape  selection = { row1, row2, col1, col2, part1, part2 }  -- part names: 'pitch'|'vel'|'delay' on note, 'pb' on pb, 'val' on scalar
    @shape  plan = { col, e, [newppq], [newEndppq], [newPpqL], [newEndppqL], [newFrame], [newDelay] }  -- consumed by writePlans / conformOverlaps
    @shape  frame = { swing = name|composite, colSwing = name|composite, rpb = int }  -- FRAME_KEYS unit; stamped onto evt.frame at authoring time

